import React, { useState, useEffect } from 'react';
import { api } from '../../contexts/AuthContext';
import ConfirmDialog from '../../components/ConfirmDialog';

const AdminScraper = () => {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [scrapedVideos, setScrapedVideos] = useState([]);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [selectedSite, setSelectedSite] = useState('91p');
  const [previewVideo, setPreviewVideo] = useState(null);
  const [confirmDialog, setConfirmDialog] = useState({
    isOpen: false,
    type: 'danger',
    title: '',
    message: '',
    onConfirm: null
  });

  // 网站配置
  const sites = [
    {
      id: '91p',
      name: '91PORNY九色',
      logo: (isSelected) => (
        <div className="flex flex-col items-center justify-center">
          <span className={`font-bold text-lg ${isSelected ? 'text-white' : 'text-gray-700'}`}>91</span>
          <span className={`font-bold text-xs ${isSelected ? 'text-white' : 'text-red-500'}`}>PORNY</span>
          <span className={`font-bold text-xs px-1 rounded ${isSelected ? 'bg-white text-red-500' : 'bg-red-500 text-white'}`}>九色</span>
        </div>
      ),
      color: 'bg-red-500'
    },
    {
      id: 'other',
      name: '其他网站',
      logo: (isSelected) => <span className="text-2xl">{isSelected ? '🌐' : '🌐'}</span>,
      color: 'bg-blue-500'
    }
  ];

  useEffect(() => {
    fetchScrapedVideos();
  }, []);

  // 自动清除提示信息
  useEffect(() => {
    if (success || error) {
      const timer = setTimeout(() => {
        setSuccess('');
        setError('');
      }, 5000); // 5秒后自动清除
      return () => clearTimeout(timer);
    }
  }, [success, error]);

  const fetchScrapedVideos = async () => {
    try {
      const response = await api.get('/admin/scraped');
      setScrapedVideos(response.data.scraped_videos);
    } catch (error) {
      console.error('Error fetching scraped videos:', error);
    }
  };

  const handleScrape = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccess('');

    try {
      await api.post('/admin/scrape', { 
        url, 
        site: selectedSite 
      });
      setSuccess('视频信息抓取成功！请在下方查看抓取结果。');
      setUrl('');
      fetchScrapedVideos();
    } catch (error) {
      console.error('Error scraping video:', error);
      setError(error.response?.data?.error || '抓取失败，请检查URL是否正确或网络连接');
    } finally {
      setLoading(false);
    }
  };

  const handleImport = async (scrapedId) => {
    try {
      await api.post(`/admin/scraped/${scrapedId}/import`);
      setSuccess('抓取的视频已成功发布到平台！');
      fetchScrapedVideos();
    } catch (error) {
      console.error('Error publishing video:', error);
      setError('发布失败，请检查网络连接后重试');
    }
  };

  const handleReject = async (scrapedId) => {
    setConfirmDialog({
      isOpen: true,
      type: 'danger',
      title: '删除抓取记录',
      message: '确定要删除这个抓取记录吗？此操作不可撤销，删除后将无法恢复抓取的视频信息。',
      onConfirm: async () => {
        try {
          // Delete the scraped video
          await api.delete(`/admin/scraped/${scrapedId}`);
          setSuccess('抓取记录已成功删除！');
          fetchScrapedVideos();
        } catch (error) {
          console.error('Error deleting video:', error);
          setError('删除失败，请重试');
        }
        setConfirmDialog(prev => ({ ...prev, isOpen: false }));
      },
      onClose: () => {
        setConfirmDialog(prev => ({ ...prev, isOpen: false }));
      }
    });
  };

  const handleSiteChange = (siteId) => {
    setSelectedSite(siteId);
    setError('');
    setSuccess('');
  };

  const handlePreview = (video) => {
    setPreviewVideo(video);
  };

  const closePreview = () => {
    setPreviewVideo(null);
  };

  const getStatusBadge = (status) => {
    const styles = {
      pending: 'bg-yellow-100 text-yellow-800',
      published: 'bg-green-100 text-green-800',
      deleted: 'bg-red-100 text-red-800'
    };

    const labels = {
      pending: '待处理',
      published: '已发布',
      deleted: '已删除'
    };

    return (
      <span className={`px-2 py-1 text-xs font-medium rounded-full ${styles[status] || 'bg-gray-100 text-gray-800'}`}>
        {labels[status] || status}
      </span>
    );
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-2xl font-bold text-gray-900">视频抓取</h1>
          <p className="text-gray-600 mt-1">从外部网站抓取视频信息并导入平台</p>
        </div>

        <div className="flex gap-6">
          {/* 纵向网站菜单 */}
          <div className="w-20 flex-shrink-0">
            <div className="bg-white rounded-xl shadow-sm p-2">
              <h3 className="text-xs font-medium text-gray-500 mb-3 text-center">选择网站</h3>
              <div className="space-y-2">
                {sites.map((site) => (
                  <button
                    key={site.id}
                    onClick={() => handleSiteChange(site.id)}
                    className={`w-full aspect-square rounded-lg flex items-center justify-center transition-all ${
                      selectedSite === site.id
                        ? `${site.color} shadow-lg scale-110`
                        : 'bg-gray-100 hover:bg-gray-200'
                    }`}
                    title={site.name}
                  >
                    {typeof site.logo === 'function' ? site.logo(selectedSite === site.id) : site.logo}
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* 主内容区域 */}
          <div className="flex-1">
            {/* Alerts */}
            {error && (
              <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg mb-6">
                {error}
              </div>
            )}
            {success && (
              <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-lg mb-6">
                {success}
              </div>
            )}

        {/* Scrape Form */}
            <div className="bg-white rounded-xl shadow-sm p-6 mb-8">
              <h2 className="text-lg font-semibold text-gray-900 mb-4">
                抓取视频 - {sites.find(s => s.id === selectedSite)?.name}
              </h2>
              <form onSubmit={handleScrape} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    视频页面URL
                  </label>
                  <input
                    type="url"
                    value={url}
                    onChange={(e) => setUrl(e.target.value)}
                    placeholder="输入视频页面URL..."
                    className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500"
                    required
                  />
                </div>
            <button
              type="submit"
              disabled={loading}
              className="bg-primary-600 text-white px-6 py-2 rounded-lg hover:bg-primary-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? (
                <span className="flex items-center">
                  <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  抓取中...
                </span>
              ) : (
                '开始抓取'
              )}
            </button>
          </form>
        </div>

        {/* Scraped Videos List */}
        <div className="bg-white rounded-xl shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-gray-200">
            <h2 className="text-lg font-semibold text-gray-900">抓取记录</h2>
          </div>

          {scrapedVideos.length > 0 ? (
            <div className="divide-y divide-gray-100">
              {scrapedVideos.map((video) => (
                <div key={video.id} className="p-6">
                  <div className="flex items-start space-x-4">
                    {/* Cover */}
                    <div className="w-32 h-20 bg-gray-900 rounded-lg overflow-hidden flex-shrink-0 cursor-pointer group" onClick={() => handlePreview(video)}>
                      {video.cover_url ? (
                        <div className="relative w-full h-full">
                          <img
                            src={video.cover_url}
                            alt={video.title}
                            className="w-full h-full object-cover"
                            onError={(e) => {
                              e.target.onerror = null;
                              e.target.src = '';
                            }}
                          />
                          <div className="absolute inset-0 bg-black/0 group-hover:bg-black/30 transition-colors flex items-center justify-center">
                            <svg className="w-8 h-8 text-white/0 group-hover:text-white/80 transition-all" fill="currentColor" viewBox="0 0 20 20">
                              <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
                            </svg>
                          </div>
                        </div>
                      ) : (
                        <div className="w-full h-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center group-hover:from-primary-500 group-hover:to-primary-700 transition-colors">
                          <svg className="w-8 h-8 text-white/50 group-hover:text-white/70 transition-colors" fill="currentColor" viewBox="0 0 20 20">
                            <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
                          </svg>
                        </div>
                      )}
                    </div>

                    {/* Info */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-start justify-between">
                        <div>
                          <h3 className="font-semibold text-gray-900 truncate">
                            {video.title || '未命名视频'}
                          </h3>
                          <p className="text-sm text-gray-500 mt-1 line-clamp-2">
                            {video.description || '暂无描述'}
                          </p>
                          <div className="flex items-center space-x-4 mt-2 text-xs text-gray-400">
                            <span className="truncate max-w-xs">{video.source_url}</span>
                            <span>•</span>
                            <span>{new Date(video.scraped_at).toLocaleDateString()}</span>
                          </div>
                        </div>
                        <div className="ml-4">
                          {getStatusBadge(video.status)}
                        </div>
                      </div>

                      {/* Actions */}
                      {video.status === 'pending' && (
                        <div className="flex space-x-2 mt-4">
                          <button
                            onClick={() => handleImport(video.id)}
                            className="px-3 py-1.5 bg-green-600 text-white text-sm rounded-lg hover:bg-green-700 transition-colors"
                          >
                            发布视频
                          </button>
                          <button
                            onClick={() => handleReject(video.id)}
                            className="px-3 py-1.5 bg-red-600 text-white text-sm rounded-lg hover:bg-red-700 transition-colors"
                          >
                            删除记录
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-16">
              <svg className="w-16 h-16 text-gray-300 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
              <h3 className="text-lg font-medium text-gray-900 mb-2">暂无抓取记录</h3>
              <p className="text-gray-500">输入视频页面URL开始抓取</p>
            </div>
          )}
        </div>

        {/* Instructions */}
        <div className="bg-blue-50 rounded-xl p-6 mt-8">
          <h3 className="text-lg font-semibold text-blue-900 mb-3">使用说明</h3>
          <ul className="space-y-2 text-sm text-blue-800">
            <li>1. 选择要抓取的网站（点击左侧网站图标）</li>
            <li>2. 输入要抓取的视频页面URL</li>
            <li>3. 系统将自动提取视频标题、简介、封面等信息</li>
            <li>4. 在抓取记录中查看提取的信息并进行预览</li>
            <li>5. 点击"发布视频"将抓取的信息添加到平台</li>
            <li>6. 发布的视频需要管理员审核后才能在前端展示</li>
          </ul>
        </div>
          </div>
        </div>
      </div>

      {/* Confirm Dialog */}
      <ConfirmDialog
        isOpen={confirmDialog.isOpen}
        type={confirmDialog.type}
        title={confirmDialog.title}
        message={confirmDialog.message}
        onConfirm={confirmDialog.onConfirm}
        onCancel={confirmDialog.onCancel || (() => setConfirmDialog(prev => ({ ...prev, isOpen: false })))}
      />

      {/* Video Preview Modal */}
      {previewVideo && (
        <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl max-w-4xl max-h-[90vh] w-full overflow-hidden">
            <div className="p-6 border-b border-gray-200">
              <div className="flex items-center justify-between">
                <h3 className="text-xl font-semibold text-gray-900">视频预览</h3>
                <button
                  onClick={closePreview}
                  className="text-gray-400 hover:text-gray-600 transition-colors"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>
            </div>

            <div className="p-6">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Video/Cover Preview */}
                <div>
                  <h4 className="text-sm font-medium text-gray-700 mb-3">视频封面</h4>
                  <div className="aspect-video bg-gray-900 rounded-lg overflow-hidden">
                    {previewVideo.cover_url ? (
                      <img
                        src={previewVideo.cover_url}
                        alt={previewVideo.title}
                        className="w-full h-full object-cover"
                        onError={(e) => {
                          e.target.onerror = null;
                          e.target.style.display = 'none';
                        }}
                      />
                    ) : (
                      <div className="w-full h-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center">
                        <svg className="w-12 h-12 text-white/50" fill="currentColor" viewBox="0 0 20 20">
                          <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
                        </svg>
                      </div>
                    )}
                  </div>
                </div>

                {/* Video Info */}
                <div>
                  <h4 className="text-sm font-medium text-gray-700 mb-3">视频信息</h4>
                  <div className="space-y-4">
                    <div>
                      <label className="block text-xs font-medium text-gray-500 mb-1">标题</label>
                      <p className="text-sm text-gray-900 bg-gray-50 rounded px-3 py-2">{previewVideo.title || '无标题'}</p>
                    </div>

                    <div>
                      <label className="block text-xs font-medium text-gray-500 mb-1">描述</label>
                      <p className="text-sm text-gray-900 bg-gray-50 rounded px-3 py-2 max-h-24 overflow-y-auto">
                        {previewVideo.description || '无描述'}
                      </p>
                    </div>

                    <div>
                      <label className="block text-xs font-medium text-gray-500 mb-1">来源URL</label>
                      <a 
                        href={previewVideo.source_url} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="text-sm text-blue-600 hover:text-blue-800 bg-blue-50 rounded px-3 py-2 block break-all"
                      >
                        {previewVideo.source_url}
                      </a>
                    </div>

                    <div>
                      <label className="block text-xs font-medium text-gray-500 mb-1">视频URL</label>
                      <p className="text-sm text-gray-900 bg-gray-50 rounded px-3 py-2 break-all">
                        {previewVideo.video_url || '未提取到视频URL'}
                      </p>
                    </div>

                    <div>
                      <label className="block text-xs font-medium text-gray-500 mb-1">封面URL</label>
                      <p className="text-sm text-gray-900 bg-gray-50 rounded px-3 py-2 break-all">
                        {previewVideo.cover_url || '未提取到封面URL'}
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminScraper;
